357→                                )}
358→                            </span>
359→                        </div>
360→                    </div>
361→                </div>
362→            </div>
363→
364→            {/* Top 15 Products Statistics - only show when no product is selected */}
365→            {!selectedProduct && !loadingTopProducts && topProducts.length > 0 && (
