399→                                                    <div
400→                                                        className="progress-bar bg-primary"
401→                                                        role="progressbar"
402→                                                        style={{ width: `${percentage}%` }}
403→                                                        aria-valuenow={percentage}
404→                                                        aria-valuemin={0}
405→                                                        aria-valuemax={100}
406→                                                    ></div>
407→                                                </div>
408→                                            </div>
409→                                        </div>
410→                                    </div>
411→                                );
412→                            })}
413→                        </div>
414→                    </div>
415→                </div>
416→            )}
417→
418→            {!selectedProduct && loadingTopProducts && (
419→                <div className="card mb-4">
420→                    <div className="card-header">
421→                        <i className="bi bi-bar-chart-fill me-2"></i>
422→                        Top 15 Products by Vulnerability Count
423→                    </div>
424→                    <div className="card-body">
425→                        <div className="d-flex justify-content-center p-3">
426→                            <div className="spinner-border spinner-border-sm text-primary" role="status">
427→                                <span className="visually-hidden">Loading top products...</span>
428→                            </div>
429→                            <span className="ms-2 text-muted">Loading statistics...</span>
430→                        </div>
431→                    </div>
432→                </div>
433→            )}
434→
435→            {/* Systems table - shown when a product is selected */}
436→            {selectedProduct && (
437→                <div className="card">
438→                    <div className="card-header d-flex justify-content-between align-items-center">
439→                        <span>
440→                            <i className="bi bi-pc-display me-2"></i>
441→                            Systems running: <strong>{selectedProduct}</strong>
442→                        </span>
443→                        <div className="d-flex align-items-center gap-2">
444→                            <span className="badge bg-primary">
445→                                {totalElements} system{totalElements !== 1 ? 's' : ''}
446→                            </span>
447→                            <button
448→                                className="btn btn-sm btn-outline-success"
449→                                onClick={handleExport}
450→                                disabled={exporting || loadingSystems || systems.length === 0}
451→                                title="Export to Excel"
452→                            >
453→                                {exporting ? (
454→                                    <>
455→                                        <span className="spinner-border spinner-border-sm me-1" role="status"></span>
456→                                        Exporting...
457→                                    </>
458→                                ) : (
459→                                    <>
460→                                        <i className="bi bi-file-earmark-excel me-1"></i>
461→                                        Export
462→                                    </>
463→                                )}
464→                            </button>
465→                        </div>
466→                    </div>
467→                    <div className="card-body">
468→                        {loadingSystems ? (
469→                            <div className="d-flex justify-content-center p-5">
470→                                <div className="spinner-border text-primary" role="status">
471→                                    <span className="visually-hidden">Loading systems...</span>
472→                                </div>
473→                            </div>
474→                        ) : systems.length === 0 ? (
475→                            <div className="alert alert-info mb-0" role="alert">
476→                                <i className="bi bi-info-circle me-2"></i>
477→                                No systems found running this product.
478→                            </div>
479→                        ) : (
480→                            <>
481→                                {/* Systems Table */}
482→                                <div className="table-responsive">
483→                                    <table className="table table-striped table-hover">
484→                                        <thead className="table-light">
485→                                            <tr>
486→                                                <th>System Name</th>
487→                                                <th>IP Address</th>
488→                                                <th>Domain</th>
489→                                            </tr>
490→                                        </thead>
491→                                        <tbody>
492→                                            {systems.map((system) => (
493→                                                <tr key={system.assetId}>
494→                                                    <td>{system.name}</td>
495→                                                    <td>{system.ip || '-'}</td>
496→                                                    <td>{system.adDomain || '-'}</td>
497→                                                </tr>
498→                                            ))}
499→                                        </tbody>
500→                                    </table>
501→                                </div>
502→
503→                                {/* Pagination */}
504→                                {totalPages > 1 && (
505→                                    <div className="d-flex justify-content-between align-items-center mt-3">
506→                                        <div className="d-flex align-items-center">
507→                                            <span className="me-2">Show:</span>
508→                                            <select
509→                                                className="form-select form-select-sm"
510→                                                style={{ width: 'auto' }}
511→                                                value={pageSize}
512→                                                onChange={handlePageSizeChange}
513→                                            >
514→                                                <option value="20">20</option>
515→                                                <option value="50">50</option>
516→                                                <option value="100">100</option>
517→                                            </select>
518→                                            <span className="ms-2 text-muted">
519→                                                Showing {currentPage * pageSize + 1} to{' '}
520→                                                {Math.min((currentPage + 1) * pageSize, totalElements)} of{' '}
521→                                                {totalElements}
522→                                            </span>
523→                                        </div>
524→                                        <nav aria-label="Systems pagination">
525→                                            <ul className="pagination mb-0">
526→                                                <li className={`page-item ${currentPage === 0 ? 'disabled' : ''}`}>
527→                                                    <button
528→                                                        className="page-link"
529→                                                        onClick={() => handlePageChange(currentPage - 1)}
530→                                                        disabled={currentPage === 0}
531→                                                    >
532→                                                        Previous
533→                                                    </button>
534→                                                </li>
535→                                                {getPageNumbers().map((page, index) => (
536→                                                    <li
537→                                                        key={index}
538→                                                        className={`page-item ${
539→                                                            page === currentPage ? 'active' : ''
540→                                                        } ${page === '...' ? 'disabled' : ''}`}
541→                                                    >
542→                                                        {page === '...' ? (
543→                                                            <span className="page-link">...</span>
544→                                                        ) : (
545→                                                            <button
546→                                                                className="page-link"
547→                                                                onClick={() => handlePageChange(page as number)}
548→                                                            >
549→                                                                {(page as number) + 1}
550→                                                            </button>
551→                                                        )}
552→                                                    </li>
553→                                                ))}
554→                                                <li
555→                                                    className={`page-item ${
556→                                                        currentPage >= totalPages - 1 ? 'disabled' : ''
557→                                                    }`}
558→                                                >
559→                                                    <button
560→                                                        className="page-link"
561→                                                        onClick={() => handlePageChange(currentPage + 1)}
562→                                                        disabled={currentPage >= totalPages - 1}
563→                                                    >
564→                                                        Next
565→                                                    </button>
566→                                                </li>
567→                                            </ul>
568→                                        </nav>
569→                                    </div>
570→                                )}
571→                            </>
572→                        )}
573→                    </div>
574→                </div>
575→            )}
576→
577→            {/* Empty state - no products */}
578→            {!selectedProduct && !loadingProducts && products.length === 0 && !searchTerm && (
