  1→/**
  2→ * OutdatedAssetsList Component
  3→ *
  4→ * Displays paginated table of assets with overdue vulnerabilities
  5→ * Features:
  6→ * - Pagination with page size selection
  7→ * - Sorting by columns
  8→ * - Search by asset name
  9→ * - Severity filter
 10→ * - Last updated timestamp
 11→ * - Refresh button
 12→ *
 13→ * Feature: 034-outdated-assets
 14→ * Task: T027-T028
 15→ * User Story: US1 - View Outdated Assets (P1)
 16→ * Spec reference: spec.md, wireframes/01-outdated-assets-list.md
 17→ */
 18→
 19→import React, { useState, useEffect } from 'react';
 20→import {
 21→  getOutdatedAssets,
 22→  getLastRefreshTimestamp,
 23→  getAdDomains,
 24→  triggerRefresh,
 25→  getRefreshStatus,
 26→  type OutdatedAsset,
 27→  type OutdatedAssetsPage,
 28→  type OutdatedAssetsParams,
 29→  type RefreshJob
 30→} from '../services/outdatedAssetsApi';
 31→import { formatDistanceToNow } from 'date-fns';
 32→
 33→const OutdatedAssetsList: React.FC = () => {
 34→  const [assets, setAssets] = useState<OutdatedAsset[]>([]);
 35→  const [loading, setLoading] = useState<boolean>(true);
 36→  const [error, setError] = useState<string | null>(null);
 37→  const [lastRefresh, setLastRefresh] = useState<string | null>(null);
 38→  const [refreshing, setRefreshing] = useState<boolean>(false);
 39→  const [refreshJob, setRefreshJob] = useState<RefreshJob | null>(null);
 40→  const [pollIntervalId, setPollIntervalId] = useState<NodeJS.Timeout | null>(null);
 41→
 42→  // Pagination state
 43→  const [currentPage, setCurrentPage] = useState<number>(0);
 44→  const [pageSize, setPageSize] = useState<number>(20);
 45→  const [totalPages, setTotalPages] = useState<number>(0);
 46→  const [totalElements, setTotalElements] = useState<number>(0);
 47→
 48→  // Filter/search state
 49→  const [searchTerm, setSearchTerm] = useState<string>('');
 50→  const [minSeverity, setMinSeverity] = useState<string>('');
 51→  const [adDomain, setAdDomain] = useState<string>('');
 52→  const [adDomainOptions, setAdDomainOptions] = useState<string[]>([]);
 53→  const [sortField, setSortField] = useState<string>('assetName');
 54→  const [sortDirection, setSortDirection] = useState<string>('asc');
 55→
 56→  /**
 57→   * Fetch outdated assets from API
 58→   */
 59→  const fetchAssets = async () => {
 60→    setLoading(true);
 61→    setError(null);
 62→
 63→    try {
 64→      const params: OutdatedAssetsParams = {
 65→        page: currentPage,
 66→        size: pageSize,
 67→        sort: `${sortField},${sortDirection}`
 68→      };
 69→
 70→      if (searchTerm.trim()) {
 71→        params.searchTerm = searchTerm.trim();
 72→      }
 73→
 74→      if (minSeverity) {
 75→        params.minSeverity = minSeverity as any;
 76→      }
 77→
 78→      if (adDomain) {
 79→        params.adDomain = adDomain;
 80→      }
 81→
 82→      const page: OutdatedAssetsPage = await getOutdatedAssets(params);
 83→
 84→      setAssets(page.content);
 85→      setTotalPages(page.totalPages);
 86→      setTotalElements(page.totalElements);
 87→      setCurrentPage(page.number);
 88→    } catch (err: any) {
 89→      console.error('Failed to fetch outdated assets:', err);
 90→      setError(err.response?.data?.message || 'Failed to load outdated assets');
 91→    } finally {
 92→      setLoading(false);
 93→    }
 94→  };
 95→
 96→  /**
 97→   * Fetch last refresh timestamp
 98→   */
 99→  const fetchLastRefresh = async () => {
100→    try {
101→      const timestamp = await getLastRefreshTimestamp();
102→      setLastRefresh(timestamp);
103→    } catch (err) {
104→      console.error('Failed to fetch last refresh timestamp:', err);
105→    }
106→  };
107→
108→  /**
109→   * Fetch available AD domains for filter dropdown
110→   */
111→  const fetchAdDomains = async () => {
112→    try {
113→      const domains = await getAdDomains();
114→      setAdDomainOptions(domains);
115→    } catch (err) {
116→      console.error('Failed to fetch AD domains:', err);
117→    }
118→  };
119→
120→  /**
121→   * Handle manual refresh trigger (async materialized view refresh)
122→   */
123→  const handleManualRefresh = async () => {
124→    try {
125→      setRefreshing(true);
126→      setError(null);
127→
128→      // Trigger async refresh
129→      const job = await triggerRefresh();
130→      setRefreshJob(job);
131→
132→      // Start polling for job status and progress
133→      pollRefreshStatus();
134→
135→    } catch (err: any) {
136→      console.error('Failed to trigger refresh:', err);
137→      setError(err.response?.data?.message || 'Failed to trigger refresh');
138→      setRefreshing(false);
139→    }
140→  };
141→
142→  /**
143→   * Poll refresh status until completion
144→   */
145→  const pollRefreshStatus = async () => {
146→    // Clear any existing poll interval
147→    if (pollIntervalId) {
148→      clearInterval(pollIntervalId);
149→    }
150→
151→    const interval = setInterval(async () => {
152→      try {
153→        const status = await getRefreshStatus();
154→
155→        if (!status) {
156→          // No job running - refresh completed or failed
157→          clearInterval(interval);
158→          setPollIntervalId(null);
159→          setRefreshing(false);
160→          setRefreshJob(null);
161→
162→          // Reload assets and timestamp
163→          fetchAssets();
164→          fetchLastRefresh();
165→          return;
166→        }
167→
168→        setRefreshJob(status);
169→
170→        if (status.status === 'COMPLETED') {
171→          clearInterval(interval);
172→          setPollIntervalId(null);
173→          setRefreshing(false);
174→
175→          // Reload assets and timestamp
176→          fetchAssets();
177→          fetchLastRefresh();
178→        } else if (status.status === 'FAILED') {
179→          clearInterval(interval);
180→          setPollIntervalId(null);
181→          setRefreshing(false);
182→          setError(status.errorMessage || 'Refresh failed');
183→        }
184→
185→      } catch (err) {
186→        console.error('Failed to poll refresh status:', err);
187→        clearInterval(interval);
188→        setPollIntervalId(null);
189→        setRefreshing(false);
190→      }
191→    }, 2000); // Poll every 2 seconds
192→
193→    setPollIntervalId(interval);
194→  };
195→
196→  /**
197→   * Handle refresh button click (simple reload)
198→   */
199→  const handleRefresh = () => {
200→    fetchAssets();
201→    fetchLastRefresh();
202→  };
203→
204→  /**
205→   * Handle sort column click
206→   */
207→  const handleSort = (field: string) => {
208→    if (field === sortField) {
209→      // Toggle direction
210→      setSortDirection(sortDirection === 'asc' ? 'desc' : 'asc');
211→    } else {
212→      // New field, default to descending
213→      setSortField(field);
214→      setSortDirection('desc');
215→    }
216→  };
217→
218→  /**
219→   * Handle page change
220→   */
221→  const handlePageChange = (newPage: number) => {
222→    setCurrentPage(newPage);
223→  };
224→
225→  /**
226→   * Handle page size change
227→   */
228→  const handlePageSizeChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
229→    setPageSize(parseInt(e.target.value, 10));
230→    setCurrentPage(0); // Reset to first page
231→  };
232→
233→  /**
234→   * Handle search
235→   */
236→  const handleSearch = (e: React.FormEvent) => {
237→    e.preventDefault();
238→    setCurrentPage(0); // Reset to first page
239→    fetchAssets();
240→  };
241→
242→  /**
243→   * Get severity badge class
244→   */
245→  const getSeverityBadgeClass = (count: number, severity: string): string => {
246→    if (count === 0) return 'badge bg-secondary';
247→
248→    switch (severity) {
249→      case 'CRITICAL':
250→        return 'badge bg-danger';
251→      case 'HIGH':
252→        return 'badge bg-warning';
253→      case 'MEDIUM':
254→        return 'badge bg-info';
255→      case 'LOW':
256→        return 'badge bg-light text-dark';
257→      default:
258→        return 'badge bg-secondary';
259→    }
260→  };
261→
262→  /**
263→   * Format time ago
264→   */
265→  const formatTimeAgo = (timestamp: string | null): string => {
266→    if (!timestamp) return 'Never';
267→    try {
268→      return formatDistanceToNow(new Date(timestamp), { addSuffix: true });
269→    } catch (err) {
270→      return 'Unknown';
271→    }
272→  };
273→
274→  // Fetch data on component mount and when filters change
275→  useEffect(() => {
276→    fetchAssets();
277→  }, [currentPage, pageSize, sortField, sortDirection, minSeverity, adDomain]);
278→
279→  // Fetch last refresh timestamp and AD domains on mount
280→  useEffect(() => {
281→    fetchLastRefresh();
282→    fetchAdDomains();
283→  }, []);
284→
285→  // Cleanup poll interval on unmount
286→  useEffect(() => {
287→    return () => {
288→      if (pollIntervalId) {
289→        clearInterval(pollIntervalId);
290→      }
291→    };
292→  }, [pollIntervalId]);
293→
294→  return (
295→    <div className="container mt-4">
296→      <div className="d-flex justify-content-between align-items-center mb-3">
297→        <h1>Outdated Assets</h1>
298→        <div>
299→          {lastRefresh && (
300→            <small className="text-muted me-3">
301→              Last updated {formatTimeAgo(lastRefresh)}
302→            </small>
303→          )}
304→          <button className="btn btn-outline-secondary me-2" onClick={handleRefresh} disabled={loading || refreshing}>
305→            <i className="bi bi-arrow-clockwise me-1"></i>
306→            Reload
307→          </button>
308→          <button
309→            className="btn btn-primary"
310→            onClick={handleManualRefresh}
311→            disabled={loading || refreshing}
312→          >
313→            {refreshing ? (
314→              <>
315→                <span className="spinner-border spinner-border-sm me-1"></span>
316→                Refreshing...
317→              </>
318→            ) : (
319→              <>
320→                <i className="bi bi-database me-1"></i>
321→                Manual Refresh
322→              </>
323→            )}
324→          </button>
325→        </div>
326→      </div>
327→
328→      {/* Refresh Progress Bar */}
329→      {refreshing && refreshJob && (
330→        <div className="alert alert-info mb-3">
331→          <div className="d-flex justify-content-between align-items-center mb-2">
332→            <span>
333→              <i className="bi bi-hourglass-split me-2"></i>
334→              Recalculating outdated assets...
335→            </span>
336→            <span className="badge bg-info">
337→              {refreshJob.assetsProcessed} / {refreshJob.totalAssets}
338→            </span>
339→          </div>
340→          <div className="progress" style={{ height: '20px' }}>
341→            <div
342→              className="progress-bar progress-bar-striped progress-bar-animated"
343→              role="progressbar"
344→              style={{ width: `${refreshJob.progressPercentage}%` }}
345→              aria-valuenow={refreshJob.progressPercentage}
346→              aria-valuemin={0}
347→              aria-valuemax={100}
348→            >
349→              {refreshJob.progressPercentage}%
350→            </div>
351→          </div>
352→        </div>
353→      )}
354→
355→      {/* Search and Filters */}
356→      <div className="card mb-3">
357→        <div className="card-body">
358→          <form onSubmit={handleSearch} className="row g-3">
359→            <div className="col-md-5">
360→              <label htmlFor="searchTerm" className="form-label">
361→                Search Asset Name
362→              </label>
363→              <input
364→                type="text"
365→                className="form-control"
366→                id="searchTerm"
367→                value={searchTerm}
368→                onChange={(e) => setSearchTerm(e.target.value)}
369→                placeholder="Search by asset name..."
370→              />
371→            </div>
372→            <div className="col-md-3">
373→              <label htmlFor="minSeverity" className="form-label">
374→                Minimum Severity
375→              </label>
376→              <select
377→                className="form-select"
378→                id="minSeverity"
379→                value={minSeverity}
380→                onChange={(e) => {
381→                  setMinSeverity(e.target.value);
382→                  setCurrentPage(0);
383→                }}
384→              >
385→                <option value="">All Severities</option>
386→                <option value="CRITICAL">Critical</option>
387→                <option value="HIGH">High or Above</option>
388→                <option value="MEDIUM">Medium or Above</option>
389→                <option value="LOW">Low or Above</option>
390→              </select>
391→            </div>
392→            <div className="col-md-2">
393→              <label htmlFor="adDomain" className="form-label">
394→                AD Domain
395→              </label>
396→              <select
397→                className="form-select"
398→                id="adDomain"
399→                value={adDomain}
400→                onChange={(e) => {
401→                  setAdDomain(e.target.value);
402→                  setCurrentPage(0);
403→                }}
404→              >
405→                <option value="">All Domains</option>
406→                {adDomainOptions.map((domain) => (
407→                  <option key={domain} value={domain}>
408→                    {domain}
409→                  </option>
410→                ))}
411→              </select>
412→            </div>
413→            <div className="col-md-2 d-flex align-items-end">
414→              <button type="submit" className="btn btn-secondary w-100" disabled={loading}>
415→                Search
416→              </button>
417→            </div>
418→          </form>
419→        </div>
420→      </div>
421→
422→      {/* Loading State */}
423→      {loading && (
424→        <div className="text-center my-5">
425→          <div className="spinner-border" role="status">
426→            <span className="visually-hidden">Loading...</span>
427→          </div>
428→        </div>
429→      )}
430→
431→      {/* Error State */}
432→      {error && (
433→        <div className="alert alert-danger" role="alert">
434→          <i className="bi bi-exclamation-triangle me-2"></i>
435→          {error}
436→        </div>
437→      )}
438→
439→      {/* Empty State */}
440→      {!loading && !error && assets.length === 0 && (
441→        <div className="alert alert-info" role="alert">
442→          <i className="bi bi-info-circle me-2"></i>
443→          No assets currently have overdue vulnerabilities.
444→        </div>
445→      )}
446→
447→      {/* Table */}
448→      {!loading && !error && assets.length > 0 && (
449→        <>
450→          <div className="table-responsive">
451→            <table className="table table-striped table-hover">
452→              <thead>
453→                <tr>
454→                  <th
455→                    style={{ cursor: 'pointer' }}
456→                    onClick={() => handleSort('assetName')}
457→                  >
458→                    Asset Name{' '}
459→                    {sortField === 'assetName' && (
460→                      <i className={`bi bi-arrow-${sortDirection === 'asc' ? 'up' : 'down'}`}></i>
461→                    )}
462→                  </th>
463→                  <th
464→                    style={{ cursor: 'pointer' }}
465→                    onClick={() => handleSort('totalOverdueCount')}
466→                  >
467→                    Overdue Count{' '}
468→                    {sortField === 'totalOverdueCount' && (
469→                      <i className={`bi bi-arrow-${sortDirection === 'asc' ? 'up' : 'down'}`}></i>
470→                    )}
471→                  </th>
472→                  <th>Severity</th>
473→                  <th
474→                    style={{ cursor: 'pointer' }}
475→                    onClick={() => handleSort('oldestVulnDays')}
476→                  >
477→                    Oldest Vuln{' '}
478→                    {sortField === 'oldestVulnDays' && (
479→                      <i className={`bi bi-arrow-${sortDirection === 'asc' ? 'up' : 'down'}`}></i>
480→                    )}
481→                  </th>
482→                </tr>
483→              </thead>
484→              <tbody>
485→                {assets.map((asset) => (
486→                  <tr
487→                    key={asset.id}
488→                    style={{ cursor: 'pointer' }}
