  1→/**
  2→ * API client for Outdated Assets endpoints
  3→ *
  4→ * Provides methods to fetch outdated assets with pagination, filtering, and sorting
  5→ * Requires authentication (ADMIN or VULN role)
  6→ *
  7→ * Feature: 034-outdated-assets
  8→ * Task: T024-T025
  9→ * User Story: US1 - View Outdated Assets (P1)
 10→ * Spec reference: contracts/01-get-outdated-assets.md
 11→ */
 12→
 13→import { authenticatedGet, authenticatedPost } from '../utils/auth';
 14→
 15→export interface OutdatedAsset {
 16→  id: number;
 17→  assetId: number;
 18→  assetName: string;
 19→  assetType: string;
 20→  totalOverdueCount: number;
 21→  criticalCount: number;
 22→  highCount: number;
 23→  mediumCount: number;
 24→  lowCount: number;
 25→  oldestVulnDays: number;
 26→  oldestVulnId: string | null;
 27→  lastCalculatedAt: string; // ISO 8601 timestamp
 28→}
 29→
 30→export interface OutdatedAssetsPage {
 31→  content: OutdatedAsset[];
 32→  totalElements: number;
 33→  totalPages: number;
 34→  size: number;
 35→  number: number; // Current page number (0-indexed)
 36→}
 37→
 38→export interface OutdatedAssetsParams {
 39→  page?: number;
 40→  size?: number;
 41→  sort?: string; // e.g., "oldestVulnDays,desc"
 42→  searchTerm?: string;
 43→  minSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
 44→  adDomain?: string;
 45→}
 46→
 47→export interface LastRefreshResponse {
 48→  lastRefreshTimestamp: string;
 49→}
 50→
 51→export interface AdDomainsResponse {
 52→  adDomains: string[];
 53→}
 54→
 55→export interface CountResponse {
 56→  count: number;
 57→}
 58→
 59→/**
 60→ * Fetch paginated list of outdated assets
 61→ *
 62→ * @param params Query parameters (page, size, sort, search, filter)
 63→ * @returns Paginated list of outdated assets
 64→ */
 65→export async function getOutdatedAssets(
 66→  params: OutdatedAssetsParams = {}
 67→): Promise<OutdatedAssetsPage> {
 68→  const queryParams = new URLSearchParams();
 69→
 70→  if (params.page !== undefined) {
 71→    queryParams.append('page', params.page.toString());
 72→  }
 73→  if (params.size !== undefined) {
 74→    queryParams.append('size', params.size.toString());
 75→  }
 76→  if (params.sort) {
 77→    queryParams.append('sort', params.sort);
 78→  }
 79→  if (params.searchTerm) {
 80→    queryParams.append('searchTerm', params.searchTerm);
 81→  }
 82→  if (params.minSeverity) {
 83→    queryParams.append('minSeverity', params.minSeverity);
 84→  }
 85→  if (params.adDomain) {
 86→    queryParams.append('adDomain', params.adDomain);
 87→  }
 88→
 89→  const url = `/api/outdated-assets${queryParams.toString() ? '?' + queryParams.toString() : ''}`;
 90→  const response = await authenticatedGet(url);
 91→  return await response.json();
