/**
 * API client for Outdated Assets endpoints
 *
 * Provides methods to fetch outdated assets with pagination, filtering, and sorting
 * Requires authentication (ADMIN or VULN role)
 *
 * Feature: 034-outdated-assets
 * Task: T024-T025
 * User Story: US1 - View Outdated Assets (P1)
 * Spec reference: contracts/01-get-outdated-assets.md
 */

import { authenticatedGet, authenticatedPost } from '../utils/auth';

export interface OutdatedAsset {
  id: number;
  assetId: number;
  assetName: string;
  assetType: string;
  totalOverdueCount: number;
  criticalCount: number;
  highCount: number;
  mediumCount: number;
  lowCount: number;
  oldestVulnDays: number;
  oldestVulnId: string | null;
  lastCalculatedAt: string; // ISO 8601 timestamp
}

export interface OutdatedAssetsPage {
  content: OutdatedAsset[];
  totalElements: number;
  totalPages: number;
  size: number;
  number: number; // Current page number (0-indexed)
}

export interface OutdatedAssetsParams {
  page?: number;
  size?: number;
  sort?: string; // e.g., "oldestVulnDays,desc"
  searchTerm?: string;
  minSeverity?: 'CRITICAL' | 'HIGH' | 'MEDIUM' | 'LOW';
  adDomain?: string;
}

export interface LastRefreshResponse {
  lastRefreshTimestamp: string;
}

export interface AdDomainsResponse {
  adDomains: string[];
}

export interface CountResponse {
  count: number;
}

/**
 * Fetch paginated list of outdated assets
 *
 * @param params Query parameters (page, size, sort, search, filter)
 * @returns Paginated list of outdated assets
 */
export async function getOutdatedAssets(
  params: OutdatedAssetsParams = {}
): Promise<OutdatedAssetsPage> {
  const queryParams = new URLSearchParams();

  if (params.page !== undefined) {
    queryParams.append('page', params.page.toString());
  }
  if (params.size !== undefined) {
    queryParams.append('size', params.size.toString());
  }
  if (params.sort) {
    queryParams.append('sort', params.sort);
  }
  if (params.searchTerm) {
    queryParams.append('searchTerm', params.searchTerm);
  }
  if (params.minSeverity) {
    queryParams.append('minSeverity', params.minSeverity);
  }
  if (params.adDomain) {
    queryParams.append('adDomain', params.adDomain);
  }

  const url = `/api/outdated-assets${queryParams.toString() ? '?' + queryParams.toString() : ''}`;
  const response = await authenticatedGet(url);
  return await response.json();
}

/**
 * Get the timestamp of the last materialized view refresh
 *
 * @returns Last refresh timestamp or null if no refresh has occurred
 */
export async function getLastRefreshTimestamp(): Promise<string | null> {
  try {
    const response = await authenticatedGet('/api/outdated-assets/last-refresh');
    if (response.status === 204) {
      return null;
    }
    const data: LastRefreshResponse = await response.json();
    return data.lastRefreshTimestamp;
  } catch (error: any) {
    // 204 No Content means no refresh has occurred yet
    if (error.response?.status === 204) {
      return null;
    }
    throw error;
  }
}

/**
 * Get distinct AD domains for filter dropdown
 *
 * @returns List of unique AD domain values
 */
export async function getAdDomains(): Promise<string[]> {
  const response = await authenticatedGet('/api/outdated-assets/ad-domains');
  const data: AdDomainsResponse = await response.json();
  return data.adDomains;
}

/**
 * Get count of outdated assets visible to current user (workgroup-filtered)
 *
 * @returns Count of outdated assets
 */
export async function getOutdatedAssetsCount(): Promise<number> {
  const response = await authenticatedGet('/api/outdated-assets/count');
  const data: CountResponse = await response.json();
  return data.count;
}

// ============================================================================
// User Story 2: View Asset Details
// ============================================================================

/**
 * Get single outdated asset by ID
 *
 * @param id Outdated asset materialized view ID
 * @returns Outdated asset details
 */
export async function getOutdatedAssetById(id: number): Promise<OutdatedAsset> {
  const response = await authenticatedGet(`/api/outdated-assets/${id}`);
  return await response.json();
}

/**
 * Vulnerability entity from backend
 */
export interface Vulnerability {
  id: number;
  vulnerabilityId: string;
  cvssSeverity: string;
  cvssscore: number | null;
  cvePublishedDate: string | null;
  vulnerableProductVersions: string | null;
  daysOpen: number;
  scanTimestamp: string;
  assetId: number;
}

/**
 * Page of vulnerabilities
 */
export interface VulnerabilitiesPage {
  content: Vulnerability[];
  totalElements: number;
  totalPages: number;
  size: number;
  number: number;
}

/**
 * Get vulnerabilities for an outdated asset
 *
 * @param id Outdated asset materialized view ID
 * @param page Page number (0-indexed)
 * @param size Page size
 * @param sort Sort string (e.g., "daysOpen,desc")
 * @returns Page of vulnerabilities for the asset
 */
export async function getAssetVulnerabilities(
  id: number,
  page: number = 0,
  size: number = 20,
  sort: string = 'daysOpen,desc'
): Promise<VulnerabilitiesPage> {
  const queryParams = new URLSearchParams();
  queryParams.append('page', page.toString());
  queryParams.append('size', size.toString());
  queryParams.append('sort', sort);

  const url = `/api/outdated-assets/${id}/vulnerabilities?${queryParams.toString()}`;
  const response = await authenticatedGet(url);
  return await response.json();
}

// ============================================================================
// User Story 3: Manual Refresh
// ============================================================================

export interface RefreshJob {
  id: number;
  status: 'RUNNING' | 'COMPLETED' | 'FAILED';
  triggeredBy: string;
  assetsProcessed: number;
  totalAssets: number;
  progressPercentage: number;
  startedAt: string;
  completedAt?: string;
  durationMs?: number;
  errorMessage?: string;
}

export interface RefreshProgressEvent {
  jobId: number;
  status: 'RUNNING' | 'COMPLETED' | 'FAILED';
  progressPercentage: number;
  assetsProcessed: number;
  totalAssets: number;
  message?: string;
}

/**
 * Trigger manual refresh of outdated assets materialized view
 * Returns immediately with job details
 *
 * @returns Refresh job details
 */
export async function triggerRefresh(): Promise<RefreshJob> {
  const response = await authenticatedPost('/api/materialized-view-refresh/trigger', {});
  return await response.json();
}

/**
 * Get current refresh job status
 *
 * @returns Current job or null if no refresh running
 */
export async function getRefreshStatus(): Promise<RefreshJob | null> {
  try {
    const response = await authenticatedGet('/api/materialized-view-refresh/status');
    if (response.status === 204) {
      return null;
    }
    return await response.json();
  } catch (error: any) {
    // 204 No Content means no refresh running
    if (error.response?.status === 204) {
      return null;
    }
    throw error;
  }
}

/**
 * Get recent refresh job history
 *
 * @returns List of recent refresh jobs
 */
export async function getRefreshHistory(): Promise<RefreshJob[]> {
  const response = await authenticatedGet('/api/materialized-view-refresh/history');
  return await response.json();
}

package com.secman.controller

import com.secman.domain.Vulnerability
import com.secman.dto.OutdatedAssetDto
import com.secman.service.OutdatedAssetService
import io.micronaut.data.model.Page
import io.micronaut.data.model.Pageable
import io.micronaut.http.HttpResponse
import io.micronaut.http.HttpStatus
import io.micronaut.http.annotation.Controller
import io.micronaut.http.annotation.Get
import io.micronaut.http.annotation.QueryValue
import io.micronaut.security.annotation.Secured
import io.micronaut.security.authentication.Authentication
import io.micronaut.security.rules.SecurityRule

/**
 * REST Controller for Outdated Assets view
 *
 * Provides paginated list of assets with overdue vulnerabilities
 * Access: ADMIN and VULN roles only
 * Returns workgroup-filtered results for VULN users
 *
 * Feature: 034-outdated-assets
 * Task: T020-T022
 * User Story: US1 - View Outdated Assets (P1)
 * Spec reference: contracts/01-get-outdated-assets.md
 */
@Controller("/api/outdated-assets")
@Secured(SecurityRule.IS_AUTHENTICATED)
class OutdatedAssetController(
    private val outdatedAssetService: OutdatedAssetService
) {

    /**
     * GET /api/outdated-assets
     *
     * Returns paginated list of outdated assets with optional filtering
     *
     * Access Control:
     * - ADMIN role: sees all outdated assets
     * - VULN role: sees only assets from assigned workgroups
     * - Other roles: 403 Forbidden
     *
     * Query Parameters:
     * - page (optional): Page number (default: 0)
     * - size (optional): Page size (default: 20)
     * - sort (optional): Sort field and direction (e.g., "oldestVulnDays,desc")
     * - searchTerm (optional): Search by asset name (case-insensitive)
     * - minSeverity (optional): Minimum severity filter (CRITICAL, HIGH, MEDIUM, LOW)
     * - adDomain (optional): AD domain filter (case-insensitive exact match)
     *
     * Response:
     * - 200 OK: Paginated list of outdated assets
     * - 401 Unauthorized: Not authenticated
     * - 403 Forbidden: User lacks ADMIN or VULN role
     *
     * Task: T020, T021, T022
     * Spec reference: FR-001, FR-008, FR-009, FR-011, FR-012, FR-013
     */
    @Get
    @Secured("ADMIN", "VULN")
    fun getOutdatedAssets(
        authentication: Authentication,
        @QueryValue(defaultValue = "") searchTerm: String?,
        @QueryValue(defaultValue = "") minSeverity: String?,
        @QueryValue(defaultValue = "") adDomain: String?,
        pageable: Pageable
    ): HttpResponse<Page<OutdatedAssetDto>> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        // Get outdated assets with workgroup filtering applied by service
        val page = outdatedAssetService.getOutdatedAssets(
            authentication = authentication,
            searchTerm = searchTerm.takeIf { !it.isNullOrBlank() },
            minSeverity = minSeverity.takeIf { !it.isNullOrBlank() },
            adDomain = adDomain.takeIf { !it.isNullOrBlank() },
            pageable = pageable
        )

        // Map to DTOs
        val dtoPage = page.map { OutdatedAssetDto.from(it) }

        return HttpResponse.ok(dtoPage)
    }

    /**
     * GET /api/outdated-assets/ad-domains
     *
     * Returns distinct AD domain values for the filter dropdown
     *
     * Response:
     * - 200 OK: { "adDomains": ["domain1.local", "domain2.local"] }
     */
    @Get("/ad-domains")
    @Secured("ADMIN", "VULN")
    fun getAdDomains(authentication: Authentication): HttpResponse<Map<String, Any>> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        val domains = outdatedAssetService.getDistinctAdDomains()
        return HttpResponse.ok(mapOf("adDomains" to domains))
    }

    /**
     * GET /api/outdated-assets/last-refresh
     *
     * Returns the timestamp of the last materialized view refresh
     *
     * Response:
     * - 200 OK: { "lastRefreshTimestamp": "2024-10-26T14:30:00" }
     * - 204 No Content: No refresh has occurred yet
     *
     * Task: T022
     * Spec reference: FR-017
     */
    @Get("/last-refresh")
    @Secured("ADMIN", "VULN")
    fun getLastRefreshTimestamp(authentication: Authentication): HttpResponse<Map<String, Any>> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        val timestamp = outdatedAssetService.getLastRefreshTimestamp()

        return if (timestamp != null) {
            HttpResponse.ok(mapOf("lastRefreshTimestamp" to timestamp))
        } else {
            HttpResponse.noContent()
        }
    }

    /**
     * GET /api/outdated-assets/count
     *
     * Returns count of outdated assets visible to the user (workgroup-filtered)
     *
     * Response:
     * - 200 OK: { "count": 42 }
     *
     * Task: T022
     * Spec reference: FR-016
     */
    @Get("/count")
    @Secured("ADMIN", "VULN")
    fun getOutdatedAssetsCount(authentication: Authentication): HttpResponse<Map<String, Any>> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        val count = outdatedAssetService.countOutdatedAssets(authentication)

        return HttpResponse.ok(mapOf("count" to count))
    }

    /**
     * GET /api/outdated-assets/{id}
     *
     * Get single outdated asset by ID with workgroup-based access control
     *
     * Access Control:
     * - ADMIN role: can access any outdated asset
     * - VULN role: can only access assets from assigned workgroups
     *
     * Response:
     * - 200 OK: OutdatedAssetDto
     * - 404 Not Found: Asset not found or user lacks access
     * - 403 Forbidden: User lacks ADMIN or VULN role
     *
     * Task: T035-T036
     * User Story: US2 - View Asset Details
     * Spec reference: contracts/02-get-outdated-asset-by-id.md
     */
    @Get("/{id}")
    @Secured("ADMIN", "VULN")
    fun getOutdatedAssetById(
        id: Long,
        authentication: Authentication
    ): HttpResponse<OutdatedAssetDto> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        // Get asset with access control
        val asset = outdatedAssetService.getOutdatedAssetById(id, authentication)
            ?: return HttpResponse.notFound()

        // Map to DTO
        val dto = OutdatedAssetDto.from(asset)

        return HttpResponse.ok(dto)
    }

    /**
     * GET /api/outdated-assets/{id}/vulnerabilities
     *
     * Get paginated list of vulnerabilities for an outdated asset
     *
     * Access Control:
     * - Requires user to have access to the outdated asset (checked via getOutdatedAssetById)
     *
     * Query Parameters:
     * - page, size, sort (standard pagination)
     *
     * Response:
     * - 200 OK: Page of vulnerabilities
     * - 404 Not Found: Asset not found or user lacks access
     * - 403 Forbidden: User lacks ADMIN or VULN role
     *
     * Task: T037-T038
     * User Story: US2 - View Asset Details
     * Spec reference: contracts/03-get-asset-vulnerabilities.md
     */
    @Get("/{id}/vulnerabilities")
    @Secured("ADMIN", "VULN")
    fun getAssetVulnerabilities(
        id: Long,
        authentication: Authentication,
        pageable: Pageable
    ): HttpResponse<Page<Vulnerability>> {
        // Validate user has required role
        val hasRequiredRole = authentication.roles.any { it == "ADMIN" || it == "VULN" }
        if (!hasRequiredRole) {
            return HttpResponse.status(HttpStatus.FORBIDDEN)
        }

        // First check if user has access to the outdated asset
        val outdatedAsset = outdatedAssetService.getOutdatedAssetById(id, authentication)
            ?: return HttpResponse.notFound()

        // Get vulnerabilities for the asset
        val vulnerabilities = outdatedAssetService.getVulnerabilitiesForAsset(
            outdatedAsset.assetId,
            pageable
        )

        return HttpResponse.ok(vulnerabilities)
    }
}

package com.secman.service

import com.secman.domain.OutdatedAssetMaterializedView
import com.secman.domain.Vulnerability
import com.secman.repository.AssetRepository
import com.secman.repository.OutdatedAssetMaterializedViewRepository
import com.secman.repository.VulnerabilityRepository
import io.micronaut.data.model.Page
import io.micronaut.data.model.Pageable
import io.micronaut.security.authentication.Authentication
import jakarta.inject.Singleton

/**
 * Service for accessing outdated assets with workgroup-based access control
 *
 * Responsibilities:
 * - Query materialized view with pagination, sorting, filtering
 * - Apply workgroup-based access control (ADMIN sees all, VULN sees assigned workgroups only)
 * - Support search and severity filtering
 *
 * Feature: 034-outdated-assets
 * Task: T016-T019
 * User Story: US1 - View Outdated Assets (P1)
 * Spec reference: spec.md FR-008, FR-009
 */
@Singleton
class OutdatedAssetService(
    private val outdatedAssetRepository: OutdatedAssetMaterializedViewRepository,
    private val vulnerabilityRepository: VulnerabilityRepository,
    private val assetRepository: AssetRepository
) {

    /**
     * Get outdated assets with workgroup-based access control
     *
     * Access Control:
     * - ADMIN role: sees all outdated assets (no filtering)
     * - VULN role: sees only assets from assigned workgroups
     * - No VULN/ADMIN: unauthorized (handled by controller @Secured)
     *
     * @param authentication Current user authentication context
     * @param searchTerm Optional search term for asset name (case-insensitive)
     * @param minSeverity Optional minimum severity filter (CRITICAL, HIGH, MEDIUM, LOW)
     * @param adDomain Optional AD domain filter (case-insensitive exact match)
     * @param pageable Pagination and sorting parameters
     * @return Page of outdated assets visible to the user
     */
    fun getOutdatedAssets(
        authentication: Authentication,
        searchTerm: String? = null,
        minSeverity: String? = null,
        adDomain: String? = null,
        pageable: Pageable
    ): Page<OutdatedAssetMaterializedView> {
        // Extract user's workgroup IDs from authentication attributes
        val workgroupIds = extractWorkgroupIds(authentication)

        // Check if user has ADMIN role - if so, they see everything
        val isAdmin = authentication.roles.contains("ADMIN")

        // Build workgroup filter parameter
        val workgroupFilter = if (isAdmin) {
            // ADMIN sees all - pass null to disable workgroup filtering
            null
        } else {
            // VULN user - filter by their assigned workgroups
            // Convert list of IDs to comma-separated string for LIKE query
            workgroupIds?.joinToString(",")
        }

        // Query repository with filters
        // Create pageable without sorting to avoid JPQL query issues
        val unsortedPageable = Pageable.from(pageable.number, pageable.size)

        return outdatedAssetRepository.findOutdatedAssets(
            workgroupId = workgroupFilter,
            searchTerm = searchTerm,
            minSeverity = minSeverity,
            adDomain = adDomain,
            pageable = unsortedPageable
        )
    }

    /**
     * Extract workgroup IDs from authentication context
     *
     * Workgroup IDs are stored in authentication attributes as "workgroupIds"
     * Expected format: List<Long>
     *
     * @param authentication User authentication context
     * @return List of workgroup IDs or null if not present
     */
    private fun extractWorkgroupIds(authentication: Authentication): List<Long>? {
        val workgroupIdsAttr = authentication.attributes["workgroupIds"] ?: return null

        return when (workgroupIdsAttr) {
            is List<*> -> workgroupIdsAttr.filterIsInstance<Long>()
            is Collection<*> -> workgroupIdsAttr.filterIsInstance<Long>()
            else -> null
        }
    }

    /**
     * Get the latest refresh timestamp
     *
     * @return Latest timestamp from materialized view, or null if no data
     */
    fun getLastRefreshTimestamp(): java.time.LocalDateTime? {
        return outdatedAssetRepository.findLatestCalculatedAt()
    }

    /**
     * Get distinct AD domains for filter dropdown
     *
     * Queries the Asset table directly to get all AD domains in the system,
     * rather than the materialized view which may not be refreshed.
     *
     * @return List of unique AD domain values, ordered alphabetically
     */
    fun getDistinctAdDomains(): List<String> {
        return assetRepository.findDistinctAdDomains()
    }

    /**
     * Count total outdated assets visible to user
