  1→/**
  2→ * React component for domain filter dropdown
  3→ *
  4→ * Displays a dropdown selector for filtering vulnerability statistics by AD domain.
  5→ * Features:
  6→ * - Fetches available domains from backend independently
  7→ * - Shows loading state while fetching
  8→ * - Shows error state with fallback to "All Domains"
  9→ * - Persists selection in sessionStorage
 10→ * - Shows asset count for selected domain
 11→ *
 12→ * Feature: 059-vuln-stats-domain-filter
 13→ * Task: T011 [US1]
 14→ * Spec reference: spec.md FR-001, FR-002, FR-003, FR-009, FR-010
 15→ * User Story: US1 - Filter Statistics by Domain (P1)
 16→ */
 17→
 18→import React, { useEffect, useState, useCallback } from 'react';
 19→import { vulnerabilityStatisticsApi, type AvailableDomainsDto } from '../../services/api/vulnerabilityStatisticsApi';
 20→
 21→/** Session storage key for domain persistence (per spec) */
 22→const STORAGE_KEY = 'secman.vuln-stats.selectedDomain';
 23→
 24→interface DomainSelectorProps {
 25→  /** Currently selected domain (null = All Domains) */
 26→  selectedDomain: string | null;
 27→  /** Callback when domain selection changes */
 28→  onDomainChange: (domain: string | null) => void;
 29→}
 30→
 31→/**
 32→ * DomainSelector component for filtering vulnerability statistics by AD domain
 33→ *
 34→ * Feature: 059-vuln-stats-domain-filter
 35→ * Task: T011 [US1], T018-T020 [US2], T021-T022 [US3]
 36→ */
 37→export default function DomainSelector({ selectedDomain, onDomainChange }: DomainSelectorProps) {
 38→  const [domainsData, setDomainsData] = useState<AvailableDomainsDto | null>(null);
 39→  const [loading, setLoading] = useState<boolean>(true);
 40→  const [error, setError] = useState<string | null>(null);
 41→
 42→  // Fetch available domains on mount
 43→  useEffect(() => {
 44→    const fetchDomains = async () => {
 45→      try {
 46→        setLoading(true);
 47→        setError(null);
 48→        const result = await vulnerabilityStatisticsApi.getAvailableDomains();
 49→        setDomainsData(result);
 50→      } catch (err) {
 51→        console.error('Error fetching available domains:', err);
 52→        setError('Failed to load domains');
 53→      } finally {
 54→        setLoading(false);
 55→      }
 56→    };
 57→
 58→    fetchDomains();
 59→  }, []);
 60→
 61→  // Read from sessionStorage on mount (US2: Persist Domain Selection)
 62→  useEffect(() => {
 63→    const storedDomain = sessionStorage.getItem(STORAGE_KEY);
 64→    if (storedDomain && storedDomain !== selectedDomain) {
 65→      onDomainChange(storedDomain);
 66→    }
 67→  }, []);
 68→
 69→  // Handle domain selection change
 70→  const handleChange = useCallback((e: React.ChangeEvent<HTMLSelectElement>) => {
 71→    const value = e.target.value;
 72→    const domain = value === '' ? null : value;
 73→
 74→    // Update parent state
 75→    onDomainChange(domain);
 76→
 77→    // Persist to sessionStorage (US2)
 78→    if (domain) {
 79→      sessionStorage.setItem(STORAGE_KEY, domain);
 80→    } else {
 81→      sessionStorage.removeItem(STORAGE_KEY);
 82→    }
 83→  }, [onDomainChange]);
 84→
 85→  // Get asset count for selected domain
 86→  const getAssetCountForDomain = (domain: string | null): number | null => {
 87→    if (!domainsData) return null;
 88→    if (domain === null) return domainsData.totalAssetCount;
 89→    // For individual domain, we'd need per-domain counts from backend
 90→    // For now, just return null for individual domains
 91→    return null;
 92→  };
 93→
 94→  // Loading state (FR-009)
 95→  if (loading) {
 96→    return (
 97→      <div className="d-flex align-items-center gap-2">
 98→        <label className="form-label mb-0 text-muted">
 99→          <i className="bi bi-building me-1"></i>
100→          Domain Filter:
101→        </label>
102→        <select className="form-select form-select-sm" style={{ width: 'auto', minWidth: '180px' }} disabled>
103→          <option>Loading domains...</option>
104→        </select>
105→        <div className="spinner-border spinner-border-sm text-muted" role="status">
106→          <span className="visually-hidden">Loading...</span>
107→        </div>
108→      </div>
109→    );
110→  }
111→
112→  // Error state (FR-010) - still allow "All Domains" to work
113→  if (error) {
114→    return (
115→      <div className="d-flex align-items-center gap-2">
116→        <label className="form-label mb-0 text-muted">
117→          <i className="bi bi-building me-1"></i>
118→          Domain Filter:
119→        </label>
120→        <select
121→          className="form-select form-select-sm is-invalid"
122→          style={{ width: 'auto', minWidth: '180px' }}
123→          value=""
124→          onChange={handleChange}
125→        >
126→          <option value="">All Domains</option>
127→        </select>
