  1→/**
  2→ * CveLink Component
  3→ *
  4→ * Renders a CVE ID as a clickable link to NVD.
  5→ * On hover (300ms delay), shows a popover with CVE description fetched from backend.
  6→ * Non-CVE IDs render as plain text.
  7→ *
  8→ * Feature: 072-cve-link-lookup
  9→ */
 10→
 11→import React, { useState, useRef, useCallback, useEffect } from 'react';
 12→import { lookupCve, type CveLookupResult } from '../services/cveLookupService';
 13→
 14→interface CveLinkProps {
 15→  cveId: string | null | undefined;
 16→}
 17→
 18→const CVE_PATTERN = /^CVE-\d{4}-\d{4,}$/;
 19→
 20→const CveLink: React.FC<CveLinkProps> = ({ cveId }) => {
 21→  const [popoverData, setPopoverData] = useState<CveLookupResult | null>(null);
 22→  const [popoverVisible, setPopoverVisible] = useState(false);
 23→  const [loading, setLoading] = useState(false);
 24→  const [popoverPosition, setPopoverPosition] = useState<'bottom' | 'top'>('bottom');
 25→  const hoverTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 26→  const hideTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 27→  const linkRef = useRef<HTMLAnchorElement>(null);
 28→  const popoverRef = useRef<HTMLDivElement>(null);
 29→
 30→  if (!cveId) {
 31→    return <span className="text-muted">-</span>;
 32→  }
 33→
 34→  const isCve = CVE_PATTERN.test(cveId);
 35→
 36→  if (!isCve) {
 37→    return <code>{cveId}</code>;
 38→  }
 39→
 40→  const nvdUrl = `https://nvd.nist.gov/vuln/detail/${cveId}`;
 41→
 42→  const showPopover = useCallback(async () => {
 43→    setPopoverVisible(true);
 44→
 45→    // Calculate position
 46→    if (linkRef.current) {
 47→      const rect = linkRef.current.getBoundingClientRect();
 48→      const spaceBelow = window.innerHeight - rect.bottom;
 49→      setPopoverPosition(spaceBelow < 200 ? 'top' : 'bottom');
 50→    }
 51→
 52→    if (popoverData) return; // Already loaded
 53→
 54→    setLoading(true);
 55→    const result = await lookupCve(cveId);
 56→    setPopoverData(result);
 57→    setLoading(false);
 58→  }, [cveId, popoverData]);
 59→
 60→  const handleMouseEnter = useCallback(() => {
 61→    if (hideTimerRef.current) {
 62→      clearTimeout(hideTimerRef.current);
 63→      hideTimerRef.current = null;
 64→    }
 65→    hoverTimerRef.current = setTimeout(showPopover, 300);
 66→  }, [showPopover]);
 67→
 68→  const handleMouseLeave = useCallback(() => {
 69→    if (hoverTimerRef.current) {
 70→      clearTimeout(hoverTimerRef.current);
 71→      hoverTimerRef.current = null;
 72→    }
 73→    hideTimerRef.current = setTimeout(() => {
 74→      setPopoverVisible(false);
 75→    }, 200);
 76→  }, []);
 77→
 78→  const handlePopoverMouseEnter = useCallback(() => {
 79→    if (hideTimerRef.current) {
 80→      clearTimeout(hideTimerRef.current);
 81→      hideTimerRef.current = null;
 82→    }
 83→  }, []);
 84→
 85→  const handlePopoverMouseLeave = useCallback(() => {
 86→    hideTimerRef.current = setTimeout(() => {
 87→      setPopoverVisible(false);
 88→    }, 200);
 89→  }, []);
 90→
 91→  // Cleanup timers on unmount
 92→  useEffect(() => {
 93→    return () => {
 94→      if (hoverTimerRef.current) clearTimeout(hoverTimerRef.current);
 95→      if (hideTimerRef.current) clearTimeout(hideTimerRef.current);
 96→    };
 97→  }, []);
 98→
 99→  const severityColor = (severity: string | null): string => {
100→    switch (severity?.toUpperCase()) {
101→      case 'CRITICAL': return '#dc3545';
102→      case 'HIGH': return '#fd7e14';
103→      case 'MEDIUM': return '#ffc107';
104→      case 'LOW': return '#28a745';
105→      default: return '#6c757d';
106→    }
107→  };
108→
109→  return (
110→    <span style={{ position: 'relative', display: 'inline-block' }}>
111→      <a
112→        ref={linkRef}
113→        href={nvdUrl}
114→        target="_blank"
115→        rel="noopener noreferrer"
116→        onMouseEnter={handleMouseEnter}
117→        onMouseLeave={handleMouseLeave}
118→        onClick={(e) => e.stopPropagation()}
119→        style={{
120→          fontFamily: 'var(--bs-font-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace)',
