 1→/**
 2→ * CVE Lookup Service
 3→ *
 4→ * Fetches CVE descriptions from backend proxy (NVD API).
 5→ * Includes in-memory cache and request deduplication.
 6→ *
 7→ * Feature: 072-cve-link-lookup
 8→ */
 9→
10→import { authenticatedGet } from '../utils/auth';
11→
12→export interface CveLookupResult {
13→  cveId: string;
14→  description: string | null;
15→  severity: string | null;
16→  cvssScore: number | null;
17→  publishedDate: string | null;
18→  references: string[];
19→}
20→
21→const cache = new Map<string, CveLookupResult>();
22→const pendingRequests = new Map<string, Promise<CveLookupResult | null>>();
23→
24→/**
25→ * Look up CVE details with caching and request deduplication.
26→ *
27→ * @param cveId CVE identifier (e.g., "CVE-2023-12345")
28→ * @returns CVE details or null if lookup fails
29→ */
30→export async function lookupCve(cveId: string): Promise<CveLookupResult | null> {
31→  // Check in-memory cache first
32→  const cached = cache.get(cveId);
33→  if (cached) return cached;
34→
35→  // Deduplicate concurrent requests for the same CVE
36→  const pending = pendingRequests.get(cveId);
37→  if (pending) return pending;
38→
39→  const request = fetchCve(cveId);
40→  pendingRequests.set(cveId, request);
41→
42→  try {
43→    const result = await request;
44→    if (result) {
45→      cache.set(cveId, result);
46→    }
47→    return result;
48→  } finally {
49→    pendingRequests.delete(cveId);
50→  }
51→}
52→
53→async function fetchCve(cveId: string): Promise<CveLookupResult | null> {
54→  try {
55→    const controller = new AbortController();
56→    const timeoutId = setTimeout(() => controller.abort(), 5000);
57→
58→    const response = await authenticatedGet(`/api/cve/${encodeURIComponent(cveId)}`);
59→    clearTimeout(timeoutId);
60→
61→    if (!response.ok) return null;
62→
63→    return await response.json();
64→  } catch {
65→    return null;
66→  }
67→}
