13→
14→/**
15→ * Get the stored user information
16→ */
17→export function getUser(): User | null {
18→    if (typeof window === 'undefined') return null;
19→    const userStr = localStorage.getItem('user');
20→    if (!userStr) return null;
21→
22→    try {
23→        return JSON.parse(userStr);
24→    } catch (e) {
25→        return null;
26→    }
27→}
28→
29→/**
30→ * Check if user is currently authenticated.
31→ * With HttpOnly cookies, we check for user data in localStorage instead of the token.
32→ * The actual authentication is validated by the server using the HttpOnly cookie.
33→ */
34→export function isAuthenticated(): boolean {
35→    // Check for user data (stored on successful login)
36→    // The actual token is in an HttpOnly cookie, not accessible via JS
37→    return getUser() !== null;
38→}
